547	    async fn wait_for_load(&self, timeout: Duration) -> Result<PageState, BrowserError> {
548	        // Poll document.readyState until complete or timeout
549	        let start = std::time::Instant::now();
550	        loop {
551	            let cmd = command::runtime_evaluate("document.readyState");
552	            if let Ok(result) = self
553	                .connection
554	                .send_command(cmd, Duration::from_secs(3))
555	                .await
556	            {
557	                if let Ok(val) = command::parse_evaluate_result(&result) {
558	                    if val.as_str() == Some("complete") {
559	                        break;
560	                    }
561	                }
562	            }
563	
564	            if start.elapsed() > timeout {
565	                return Err(BrowserError::NavigationTimeout(timeout));
566	            }
567	            tokio::time::sleep(Duration::from_millis(200)).await;
568	        }
569	
570	        let current_url = self.current_url.lock().await.clone();
571	        Ok(PageState {
572	            url: current_url,
573	            title: String::new(),
574	            loaded: true,
575	            dom_node_count: 0,
576	            visible_text: vec![],
577	            timestamp: chrono::Utc::now(),
578	        })
579	    }
