1	//! Anti-detection engine for the Agent Nervous System.
2	//!
3	//! Protects Chromium instances from bot detection by masking browser
4	//! automation signals at three layers:
5	//!
6	//! - **Launch flags**: Chrome CLI flags that suppress automation markers
7	//! - **CDP patches**: JavaScript injected before page scripts via
8	//!   `Page.addScriptToEvaluateOnNewDocument`
9	//! - **Behavioral**: Humanized mouse movement (bezier curves) and
10	//!   variable typing delays
11	//!
12	//! # Adaptive escalation
13	//!
14	//! The engine integrates with the 5 Eyes perception layer. When the
15	//! Error Detector flags a page as bot-detected (Cloudflare, captcha,
16	//! DataDome), the stealth level can be escalated dynamically:
17	//!
18	//! ```text
19	//! Off → Standard → Aggressive → Paranoid
20	//! ```
21	//!
22	//! Each level adds more evasion techniques. Higher levels cost more
23	//! CPU (canvas/WebGL spoofing, deeper DOM patches).
24	//!
25	//! # Fingerprint consistency
26	//!
27	//! Unlike `puppeteer-extra-plugin-stealth` which randomizes per page,
28	//! ANS maintains per-session fingerprint consistency — the same
29	//! browser identity across all pages in a session. This matches
30	//! real user behavior (you don't change GPUs between tabs).
31	
32	pub mod flags;
33	pub mod humanize;
34	pub mod patches;
35	pub mod profiles;
36	
37	use serde::{Deserialize, Serialize};
38	
39	pub use profiles::FingerprintProfile;
40	
41	/// Stealth configuration, created once per browser session.
42	#[derive(Debug, Clone, Serialize, Deserialize)]
43	pub struct StealthConfig {
44	    /// Current evasion level. May be escalated dynamically.
45	    pub level: StealthLevel,
46	    /// Browser fingerprint profile (consistent per session).
47	    pub profile: FingerprintProfile,
48	    /// Enable humanized mouse/keyboard behavior.
49	    pub humanize: bool,
50	    /// Enable adaptive escalation (auto-escalate on bot detection).
51	    pub adaptive: bool,
52	}
53	
54	impl Default for StealthConfig {
55	    fn default() -> Self {
56	        Self {
57	            level: StealthLevel::Standard,
58	            profile: FingerprintProfile::windows_chrome(),
59	            humanize: true,
60	            adaptive: true,
61	        }
62	    }
63	}
64	
65	impl StealthConfig {
66	    /// Create a stealth config suitable for production use.
67	    /// Standard level with Windows Chrome profile.
68	    #[must_use]
69	    pub fn standard() -> Self {
70	        Self::default()
71	    }
72	
73	    /// Maximum stealth — paranoid level with all evasions.
74	    #[must_use]
75	    #[allow(dead_code)]
76	    pub fn paranoid() -> Self {
77	        Self {
78	            level: StealthLevel::Paranoid,
79	            profile: FingerprintProfile::windows_chrome().with_random_variation(),
80	            humanize: true,
81	            adaptive: false,
82	        }
83	    }
84	
85	    /// Create a config suitable for internal/trusted pages.
86	    /// Disables all stealth (faster, no overhead).
87	    #[must_use]
88	    pub fn off() -> Self {
89	        Self {
90	            level: StealthLevel::Off,
91	            ..Self::default()
92	        }
93	    }
94	
95	    /// Get Chrome CLI flags for the current level.
96	    #[must_use]
97	    pub fn chrome_flags(&self) -> Vec<String> {
98	        flags::chrome_flags(self.level)
99	    }
100	
101	    /// Get CDP init scripts for the current level.
102	    #[must_use]
103	    pub fn init_scripts(&self) -> Vec<String> {
104	        patches::init_scripts(self.level, &self.profile)
105	    }
106	
107	    /// Get the self-audit script that verifies evasions are working.
108	    #[must_use]
109	    pub fn audit_script() -> String {
110	        patches::audit_script()
111	    }
112	
113	    /// Escalate stealth level if adaptive mode is enabled.
114	    /// Called when the Error Detector (5 Eyes) flags bot detection.
115	    pub fn escalate(&mut self) {
116	        if !self.adaptive {
117	            return;
118	        }
119	        self.level = self.level.escalate();
120	        tracing::warn!(
121	            level = ?self.level,
122	            "Stealth level escalated due to bot detection signal"
123	        );
124	    }
125	
126	    /// De-escalate stealth level (called after leaving a protected page).
127	    pub fn de_escalate(&mut self) {
128	        self.level = self.level.de_escalate();
129	    }
130	}
131	
132	/// Stealth level — how aggressively to evade detection.
133	///
134	/// Levels are ordered: higher = more evasion, more CPU cost.
135	#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
136	pub enum StealthLevel {
137	    /// No stealth — use for internal/trusted pages. Zero overhead.
138	    Off = 0,
139	    /// Core evasions only — webdriver, chrome, plugins, languages.
140	    /// Covers ~90% of detection vectors. Minimal overhead.
141	    Standard = 1,
142	    /// Full evasions — adds canvas, audio, WebGL spoofing.
143	    /// Moderate CPU overhead (~5%).
144	    Aggressive = 2,
145	    /// All evasions including experimental patches.
146	    /// May affect page behavior slightly. Highest CPU cost (~10%).
147	    Paranoid = 3,
148	}
149	
150	impl StealthLevel {
151	    /// Escalate to the next level. Cannot go above Paranoid.
152	    #[must_use]
153	    pub fn escalate(self) -> Self {
154	        match self {
155	            Self::Off => Self::Standard,
156	            Self::Standard => Self::Aggressive,
157	            Self::Aggressive | Self::Paranoid => Self::Paranoid,
158	        }
159	    }
160	
161	    /// De-escalate to the previous level. Cannot go below Off.
162	    #[must_use]
163	    pub fn de_escalate(self) -> Self {
164	        match self {
165	            Self::Off | Self::Standard => Self::Off,
166	            Self::Aggressive => Self::Standard,
167	            Self::Paranoid => Self::Aggressive,
168	        }
169	    }
170	}
