66	/// Self-audit script that checks whether key evasions are working.
67	/// Returns JSON with pass/fail for each vector.
68	#[must_use]
69	pub fn audit_script() -> String {
70	    r#"
71	(function() {
72	    var results = {};
73	    try {
74	        results.webdriver = navigator.webdriver === undefined || navigator.webdriver === false;
75	    } catch(e) { results.webdriver = false; }
76	    try {
77	        results.chrome = typeof window.chrome === 'object' && window.chrome !== null;
78	    } catch(e) { results.chrome = false; }
79	    try {
80	        var p = navigator.plugins;
81	        results.plugins = p && p.length > 0;
82	    } catch(e) { results.plugins = false; }
83	    try {
84	        results.languages = navigator.languages && navigator.languages.length > 0;
85	    } catch(e) { results.languages = false; }
86	    try {
87	        results.hardwareConcurrency = navigator.hardwareConcurrency > 0;
88	    } catch(e) { results.hardwareConcurrency = false; }
89	    try {
90	        results.deviceMemory = navigator.deviceMemory > 0;
91	    } catch(e) { results.deviceMemory = false; }
92	    try {
93	        results.outerDims = window.outerWidth > window.innerWidth;
94	    } catch(e) { results.outerDims = false; }
95	    return JSON.stringify(results);
96	})()
97	"#
98	    .to_string()
99	}
100	
101	// ── Individual patches ─────────────────────────────────────────────
102	
103	fn patch_navigator_webdriver() -> String {
104	    r#"
105	(function() {
106	    if (navigator.webdriver === undefined) return;
107	    Object.defineProperty(Object.getPrototypeOf(navigator), 'webdriver', {
108	        get: function() { return false; },
109	        set: function() {},
110	        configurable: true,
111	        enumerable: true
112	    });
113	})();
114	"#
115	    .to_string()
116	}
117	
118	fn patch_chrome_runtime() -> String {
119	    r#"
120	(function() {
121	    if (typeof window.chrome !== 'undefined' && window.chrome && window.chrome.runtime) return;
122	    var c = window.chrome || {};
123	    c.runtime = c.runtime || {};
