1	//! Fingerprint profiles — per-session consistent browser identity.
2	//!
3	//! Each session gets a randomly selected profile that remains
4	//! consistent across all pages within that session. This mimics
5	//! how a real user doesn't change hardware between pages.
6	//!
7	//! Profiles include: screen dimensions, WebGL GPU strings,
8	//! platform, language preferences, timezone, and color depth.
9	
10	use serde::{Deserialize, Serialize};
11	
12	/// A complete browser fingerprint profile.
13	///
14	/// All values in this profile are applied to every page in a session.
15	/// The profile is generated once at session creation and never changes.
16	#[derive(Debug, Clone, Serialize, Deserialize)]
17	pub struct FingerprintProfile {
18	    /// Reported WebGL vendor string (e.g., "Google Inc. (Intel)")
19	    pub webgl_vendor: String,
20	    /// Reported WebGL renderer string (e.g., "ANGLE (Intel, ...)")
21	    pub webgl_renderer: String,
22	    /// Screen width in pixels
23	    pub screen_width: u32,
24	    /// Screen height in pixels
25	    pub screen_height: u32,
26	    /// Color depth (24 or 30)
27	    pub color_depth: u32,
28	    /// Platform string (Win32, MacIntel, Linux x86_64)
29	    pub platform: String,
30	    /// Preferred languages
31	    pub languages: Vec<String>,
32	    /// Timezone identifier
33	    pub timezone: String,
34	}
35	
36	impl FingerprintProfile {
37	    /// A realistic Windows 11 + Chrome profile with Intel GPU.
38	    #[must_use]
39	    pub fn windows_chrome() -> Self {
40	        Self {
41	            webgl_vendor: "Google Inc. (Intel)".into(),
42	            webgl_renderer: "ANGLE (Intel, Intel(R) UHD Graphics (0x00009A60) Direct3D11 vs_5_0 ps_5_0, D3D11)".into(),
43	            screen_width: 1920,
44	            screen_height: 1080,
45	            color_depth: 24,
46	            platform: "Win32".into(),
47	            languages: vec!["en-US".into(), "en".into()],
48	            timezone: "America/New_York".into(),
49	        }
50	    }
51	
52	    /// A realistic macOS + Chrome profile with Apple M-series GPU.
53	    #[must_use]
54	    #[allow(dead_code)]
55	    pub fn mac_chrome() -> Self {
56	        Self {
57	            webgl_vendor: "Google Inc. (Apple)".into(),
58	            webgl_renderer: "ANGLE (Apple, Apple M2, OpenGL 4.1)".into(),
59	            screen_width: 1728,
60	            screen_height: 1117,
61	            color_depth: 30,
62	            platform: "MacIntel".into(),
63	            languages: vec!["en-US".into(), "en".into()],
64	            timezone: "America/Los_Angeles".into(),
65	        }
66	    }
67	
68	    /// A realistic Linux + Chrome profile.
69	    #[must_use]
70	    #[allow(dead_code)]
71	    pub fn linux_chrome() -> Self {
72	        Self {
73	            webgl_vendor: "Google Inc. (Mesa)".into(),
74	            webgl_renderer: "ANGLE (Mesa, Mesa Intel(R) UHD Graphics (ICL GT1), OpenGL 4.6)".into(),
75	            screen_width: 1920,
76	            screen_height: 1080,
77	            color_depth: 24,
78	            platform: "Linux x86_64".into(),
79	            languages: vec!["en-US".into(), "en".into()],
80	            timezone: "America/Chicago".into(),
81	        }
82	    }
83	
84	    /// Randomize minor variations within a profile to avoid identical
85	    /// fingerprints across sessions. Call once per session.
86	    #[must_use]
87	    #[allow(dead_code)]
88	    pub fn with_random_variation(&self) -> Self {
89	        let resolutions: [(u32, u32); 4] = [
90	            (1920, 1080),
91	            (1920, 1200),
92	            (2560, 1440),
93	            (1680, 1050),
94	        ];
95	        let pick = fast_index(resolutions.len());
96	        let (w, h) = resolutions[pick];
97	
98	        let depths: [u32; 2] = [24, 30];
99	        let cd = depths[fast_index(depths.len())];
100	
101	        Self {
102	            screen_width: w,
103	            screen_height: h,
104	            color_depth: cd,
105	            ..self.clone()
106	        }
107	    }
108	}
109	
110	// ── Minimal RNG for profile selection ──────────────────────────────
111	
112	fn fast_index(max: usize) -> usize {
113	    if max <= 1 { return 0; }
114	    use std::time::{SystemTime, UNIX_EPOCH};
115	    let nanos = SystemTime::now()
116	        .duration_since(UNIX_EPOCH)
117	        .map(|d| d.as_nanos())
118	        .unwrap_or(0);
119	    (nanos as usize) % max
120	}
