1	//! Human-like input behavior for mouse and keyboard.
2	//!
3	//! Generates bezier curve paths for mouse movement and variable
4	//! typing delays based on character frequency (common letters = faster).
5	
6	use std::time::Duration;
7	
8	/// Generate a bezier-based mouse path from (x1,y1) to (x2,y2).
9	///
10	/// Returns a vector of intermediate points plus the destination.
11	/// Each step represents ~8ms of movement for realistic cursor
12	/// velocity (~500px/s average).
13	#[must_use]
14	pub fn bezier_path(
15	    from: (f64, f64),
16	    to: (f64, f64),
17	) -> Vec<(f64, f64)> {
18	    let dx = to.0 - from.0;
19	    let dy = to.1 - from.1;
20	    let dist = (dx * dx + dy * dy).sqrt();
21	
22	    if dist < 5.0 {
23	        return vec![to];
24	    }
25	
26	    // Control points: random offset perpendicular to the line
27	    let angle = dy.atan2(dx);
28	    let perp = angle + std::f64::consts::FRAC_PI_2;
29	
30	    // Random offset magnitude proportional to distance
31	    let offset = dist * 0.15 * fast_random();
32	    let wobble_x = offset * perp.cos();
33	    let wobble_y = offset * perp.sin();
34	
35	    let cp1 = (from.0 + dx * 0.33 + wobble_x, from.1 + dy * 0.33 + wobble_y);
36	    let cp2 = (from.0 + dx * 0.66 - wobble_x, from.1 + dy * 0.66 - wobble_y);
37	
38	    // Number of steps based on distance (realistic: ~500px/s, ~8ms/step)
39	    let steps = (dist / 4.0) as usize;
40	    let steps = steps.clamp(8, 120);
41	
42	    let mut path = Vec::with_capacity(steps + 1);
43	    for i in 0..steps {
44	        let t = (i + 1) as f64 / steps as f64;
45	        // Cubic bezier: B(t) = (1-t)^3*P0 + 3(1-t)^2*t*P1 + 3(1-t)*t^2*P2 + t^3*P3
46	        let mt = 1.0 - t;
47	        let x = mt * mt * mt * from.0
48	            + 3.0 * mt * mt * t * cp1.0
49	            + 3.0 * mt * t * t * cp2.0
50	            + t * t * t * to.0;
51	        let y = mt * mt * mt * from.1
52	            + 3.0 * mt * mt * t * cp1.1
53	            + 3.0 * mt * t * t * cp2.1
54	            + t * t * t * to.1;
55	
56	        // Add micro-jitter: human hand tremor (sub-pixel)
57	        let jitter_x = (fast_random() - 0.5) * 0.8;
58	        let jitter_y = (fast_random() - 0.5) * 0.8;
59	
60	        path.push((x + jitter_x, y + jitter_y));
61	    }
62	
63	    path
64	}
65	
66	/// Human-like typing delay for a given character.
67	///
68	/// Common letters (e, t, a, o, i, n, s, h, r) get 40-80ms.
69	/// Rare letters get 60-120ms.
70	/// Space and punctuation get 30-60ms.
71	/// Uppercase adds shift-key overhead.
72	#[must_use]
73	pub fn typing_delay(c: char, _total_chars_typed: usize) -> Duration {
74	    let base_ms = match c {
75	        ' ' | '.' | ',' | ';' => fast_random_range(30.0, 60.0),
76	        'e' | 't' | 'a' | 'o' | 'i' | 'n' | 's' | 'h' | 'r' => {
77	            fast_random_range(40.0, 80.0)
78	        }
79	        _ if c.is_uppercase() => fast_random_range(70.0, 140.0), // shift overhead
80	        _ => fast_random_range(60.0, 120.0),
81	    };
82	    Duration::from_millis(base_ms as u64)
83	}
84	
85	/// Random delay between actions (think time).
86	#[must_use]
87	pub fn think_delay() -> Duration {
88	    Duration::from_millis(fast_random_range(200.0, 800.0) as u64)
89	}
90	
91	/// Random delay after a click (reaction time).
92	#[must_use]
93	pub fn click_linger() -> Duration {
94	    Duration::from_millis(fast_random_range(150.0, 400.0) as u64)
95	}
96	
97	/// Sub-pixel position jitter for click coordinates.
98	/// Prevents clicking the exact center of elements every time.
99	#[must_use]
100	pub fn position_jitter() -> f64 {
101	    (fast_random() - 0.5) * 4.0
102	}
103	
104	// ── Internal fast RNG (no crypto needed for humanization) ──────────
105	
106	fn fast_random() -> f64 {
107	    // Simple xorshift — fast, no allocation, good enough for jitter
108	    use std::cell::Cell;
109	    thread_local! {
110	        static STATE: Cell<u64> = Cell::new(0xDEAD_BEEF_CAFE_BABE);
111	    }
112	    STATE.with(|state| {
113	        let mut x = state.get();
114	        if x == 0 { x = 0xDEAD_BEEF_CAFE_BABE; }
115	        x ^= x << 13;
116	        x ^= x >> 7;
117	        x ^= x << 17;
118	        state.set(x);
119	        (x as f64) / (u64::MAX as f64)
120	    })
121	}
122	
123	fn fast_random_range(min: f64, max: f64) -> f64 {
124	    min + fast_random() * (max - min)
125	}
126	
127	#[cfg(test)]
128	mod tests {
129	    use super::*;
130	
131	    #[test]
132	    fn test_bezier_short_path() {
133	        let path = bezier_path((100.0, 100.0), (102.0, 102.0));
134	        assert_eq!(path.len(), 1);
135	        assert_eq!(path[0], (102.0, 102.0));
136	    }
137	
138	    #[test]
139	    fn test_bezier_long_path() {
140	        let path = bezier_path((0.0, 0.0), (500.0, 300.0));
141	        // Should have many intermediate points
142	        assert!(path.len() > 10);
143	        // Last point should be very close to destination
144	        let last = path.last().expect("bezier_path always returns at least one point");
145	        assert!((last.0 - 500.0).abs() < 3.0);
146	        assert!((last.1 - 300.0).abs() < 3.0);
147	    }
148	
149	    #[test]
150	    fn test_bezier_points_are_monotonic_ish() {
151	        let path = bezier_path((0.0, 0.0), (100.0, 100.0));
152	        // Path should generally progress toward destination
153	        for i in 1..path.len() {
154	            let prev = path[i - 1];
155	            let curr = path[i];
156	            let dist_before = (prev.0 * prev.0 + prev.1 * prev.1).sqrt();
157	            let dist_after = (curr.0 * curr.0 + curr.1 * curr.1).sqrt();
158	            // Points get further from origin (generally)
159	            assert!(
160	                dist_after > dist_before - 2.0,
161	                "point {i} ({curr:?}) moved backwards from {prev:?}"
162	            );
163	        }
164	    }
165	
166	    #[test]
167	    fn test_typing_delay_reasonable() {
168	        for c in ['e', 'A', ' ', 'q'] {
169	            let delay = typing_delay(c, 0);
170	            assert!(delay.as_millis() >= 30, "delay for '{c}' too short");
171	            assert!(delay.as_millis() <= 150, "delay for '{c}' too long");
172	        }
173	    }
174	
175	    #[test]
176	    fn test_think_delay_reasonable() {
177	        for _ in 0..10 {
178	            let d = think_delay();
179	            assert!(d.as_millis() >= 200);
180	            assert!(d.as_millis() <= 800);
181	        }
182	    }
183	}
