1	//! Agent Nervous System daemon entry point.
2	//!
3	//! Starts two servers:
4	//! - gRPC server on loopback:50051 (internal Python/TS clients)
5	//! - Gateway on loopback:50052 (external AI agents — MCP, REST, WS)
6	//!
7	//! Both run concurrently. Chromium instances are cleaned up on exit
8	//! via RAII drop guards. Ctrl+C triggers graceful shutdown.
9	
10	use std::net::{IpAddr, Ipv4Addr, SocketAddr};
11	use std::path::PathBuf;
12	
13	use ans_ipc::IpcServer;
14	use clap::Parser;
15	use tracing_subscriber::EnvFilter;
16	
17	#[derive(Parser)]
18	#[command(name = "ans-daemon", version, about = "Agent Nervous System daemon")]
19	struct Cli {
20	    /// gRPC port to bind on loopback
21	    #[arg(long, default_value = "50051")]
22	    grpc_port: u16,
23	
24	    /// Gateway port to bind on loopback
25	    #[arg(long, default_value = "50052")]
26	    gateway_port: u16,
27	
28	    /// Path to ans.toml configuration file
29	    #[arg(long, default_value = "ans.toml")]
30	    config: PathBuf,
31	
32	    /// Path to nerves/ directory (Python intelligence layer)
33	    #[arg(long, default_value = "nerves")]
34	    nerves_dir: PathBuf,
35	
36	    /// Number of Chromium instances to pre-warm (default 2, 0 to disable)
37	    #[arg(long, default_value = "2")]
38	    prewarm: usize,
39	}
40	
41	#[tokio::main]
42	async fn main() {
43	    if let Err(e) = color_eyre::install() {
44	        eprintln!("Failed to install color-eyre panic handler: {e}");
45	        std::process::exit(1);
46	    }
47	
48	    let cli = Cli::parse();
49	
50	    tracing_subscriber::fmt()
51	        .with_env_filter(
52	            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("ans=debug,info")),
53	        )
54	        .init();
55	
56	    tracing::info!(version = env!("CARGO_PKG_VERSION"), "ans-daemon starting");
57	
58	    if let Some(cfg) = load_config(&cli.config) {
59	        tracing::info!(?cfg, "Config loaded");
60	    } else {
61	        tracing::info!("No config file found, using defaults");
62	    }
63	
64	    // ── Start gRPC server in background ──────────────────────────────
65	    let nerves_abs = if cli.nerves_dir.is_absolute() {
66	        cli.nerves_dir.clone()
67	    } else {
68	        std::env::current_dir().unwrap_or_default().join(&cli.nerves_dir)
69	    };
70	    let server = IpcServer::new()
71	        .with_nerves_dir(nerves_abs)
72	        .with_pool_size(cli.prewarm);
73	    let goal_store = server.goal_store(); // clone before server moves into spawn
74	    let grpc_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.grpc_port);
75	
76	    let grpc_handle = tokio::spawn(async move {
77	        if let Err(e) = server.serve(grpc_addr).await {
78	            tracing::error!(%e, "gRPC server exited with error");
79	        }
80	    });
81	
82	    // Give the gRPC server a moment to bind before starting the gateway
83	    tokio::time::sleep(std::time::Duration::from_millis(300)).await;
84	
85	    // ── Start gateway ────────────────────────────────────────────────
86	    let gw_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.gateway_port);
87	
88	    let gw_handle = match ans_gateway::Gateway::init(cli.grpc_port, Some(goal_store)).await {
89	        Ok(gateway) => {
90	            tracing::info!("Gateway starting on {}", gw_addr);
91	            tokio::spawn(async move {
92	                if let Err(e) = gateway.serve(gw_addr).await {
93	                    tracing::error!(%e, "Gateway exited with error");
94	                }
95	            })
96	        }
97	        Err(e) => {
98	            tracing::warn!(%e, "Gateway failed to initialize — running gRPC-only");
99	            // Still wait for gRPC server
100	            let _ = grpc_handle.await;
101	            return;
102	        }
103	    };
104	
105	    // ── Wait for shutdown ────────────────────────────────────────────
106	    tokio::select! {
107	        _ = tokio::signal::ctrl_c() => {
108	            tracing::info!("Shutdown signal received");
109	        }
110	        _ = grpc_handle => {
111	            tracing::warn!("gRPC server exited unexpectedly");
112	        }
113	        _ = gw_handle => {
114	            tracing::warn!("Gateway exited unexpectedly");
115	        }
116	    }
117	
118	    tracing::info!("ans-daemon shut down cleanly");
119	}
120	
121	fn load_config(path: &PathBuf) -> Option<toml::Value> {
122	    let content = std::fs::read_to_string(path).ok()?;
123	    toml::from_str(&content).ok()
124	}
