1	//! Session manager for goal-scoped browser sessions.
2	//!
3	//! Each session wraps a [`CdpBackend`] (Chromium instance) and is
4	//! identified by a UUID. Sessions are organized by goal — not by tab —
5	//! and share the same goal state store.
6	
7	use std::collections::HashMap;
8	use std::sync::Arc;
9	use std::time::Duration;
10	
11	use ans_cdp::CdpBackend;
12	use ans_core::backend::{BrowserBackend, BrowserError, ImageFormat, PageState};
13	use ans_core::distill::{DistillMode, DistilledPage};
14	use ans_core::session::{Action, ActionOutcome, SessionStatus};
15	use tokio::sync::RwLock;
16	use tracing;
17	use uuid::Uuid;
18	
19	use crate::pool::BrowserPool;
20	
21	/// Handle to an active browser session.
22	pub struct SessionHandle {
23	    pub session_id: Uuid,
24	    pub goal_id: Uuid,
25	    pub backend: CdpBackend,
26	    pub current_url: String,
27	    pub status: SessionStatus,
28	}
29	
30	/// Thread-safe session registry.
31	///
32	/// Cloning shares the underlying `Arc<RwLock<>>` — all references
33	/// see the same sessions.
34	#[derive(Clone)]
35	pub struct SessionManager {
36	    sessions: Arc<RwLock<HashMap<Uuid, SessionHandle>>>,
37	    pool: BrowserPool,
38	}
39	
40	impl Default for SessionManager {
41	    fn default() -> Self {
42	        Self::new()
43	    }
44	}
45	
46	impl SessionManager {
47	    #[must_use]
48	    pub fn new() -> Self {
49	        Self {
50	            sessions: Arc::new(RwLock::new(HashMap::new())),
51	            pool: BrowserPool::new(2),
52	        }
53	    }
54	
55	    /// Create a session manager with a specific pool size.
56	    #[must_use]
57	    pub fn with_pool_size(pool_size: usize) -> Self {
58	        Self {
59	            sessions: Arc::new(RwLock::new(HashMap::new())),
60	            pool: BrowserPool::new(pool_size),
61	        }
62	    }
63	
64	    /// Create a new session by launching a Chromium instance.
65	    /// If `start_url` is provided, navigate to it immediately.
66	    pub async fn create(
67	        &self,
68	        goal_id: Uuid,
69	        start_url: Option<String>,
70	    ) -> Result<Uuid, BrowserError> {
71	        let session_id = Uuid::new_v4();
72	        tracing::info!(%session_id, %goal_id, "Creating session");
73	
74	        let backend = self.pool.acquire().await?;
75	
76	        if let Some(url) = &start_url {
77	            let _ = backend
78	                .navigate(url, Duration::from_secs(10))
79	                .await
80	                .map(|state| {
81	                    tracing::info!(url = %state.url, "Session started at URL");
82	                });
83	        }
84	
85	        let handle = SessionHandle {
86	            session_id,
87	            goal_id,
88	            backend,
89	            current_url: start_url.unwrap_or_else(|| "about:blank".into()),
90	            status: SessionStatus::Idle,
91	        };
92	
93	        self.sessions.write().await.insert(session_id, handle);
94	
95	        Ok(session_id)
96	    }
97	
98	    /// Close a session and kill its Chromium process.
99	    pub async fn close(&self, session_id: Uuid) -> Result<(), BrowserError> {
100	        tracing::info!(%session_id, "Closing session");
101	        let handle = self.sessions.write().await.remove(&session_id);
102	        if let Some(handle) = handle {
103	            self.pool.release(handle.backend).await;
104	        }
105	        Ok(())
106	    }
107	
108	    /// Close all active sessions.
109	    pub async fn close_all(&self) {
110	        let ids: Vec<Uuid> = self.sessions.read().await.keys().copied().collect();
111	        for id in ids {
112	            let _ = self.close(id).await;
113	        }
114	        tracing::info!("All sessions closed");
115	    }
116	
117	    /// Execute an action on a session.
118	    pub async fn execute_action(
119	        &self,
120	        session_id: Uuid,
121	        action: &Action,
122	    ) -> Result<ActionOutcome, BrowserError> {
123	        let sessions = self.sessions.read().await;
124	        let handle = sessions
125	            .get(&session_id)
126	            .ok_or(BrowserError::BrowserClosed)?;
127	
128	        let outcome = match action.action_type {
129	            ans_core::session::ActionType::Click => {
130	                let selector = action
131	                    .selector
132	                    .as_deref()
133	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
134	                handle.backend.click(selector).await?
135	            }
136	            ans_core::session::ActionType::Type => {
137	                let selector = action
138	                    .selector
139	                    .as_deref()
140	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
141	                let text = action.value.as_deref().unwrap_or("");
142	                handle.backend.type_text(selector, text).await?
143	            }
144	            ans_core::session::ActionType::Scroll => {
145	                let pixels = action.value.as_deref().and_then(|v| v.parse().ok());
146	                let selector = action.selector.as_deref();
147	                handle.backend.scroll(pixels, selector).await?
148	            }
149	            ans_core::session::ActionType::Select => {
150	                let selector = action
151	                    .selector
152	                    .as_deref()
153	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
154	                let value = action.value.as_deref().unwrap_or("");
155	                handle.backend.select_option(selector, value).await?
156	            }
157	            ans_core::session::ActionType::Navigate => {
158	                let url = action
159	                    .value
160	                    .as_deref()
161	                    .ok_or_else(|| BrowserError::CdpProtocol("missing URL".into()))?;
162	                let state = handle
163	                    .backend
164	                    .navigate(url, Duration::from_secs(10))
165	                    .await?;
166	                ActionOutcome {
167	                    success: true,
168	                    error_message: None,
169	                    execution_time_ms: 0,
170	                    page_url_after: Some(state.url),
171	                    dom_changed: false,
172	                }
173	            }
174	            ans_core::session::ActionType::Wait => {
175	                let ms = action
176	                    .value
177	                    .as_deref()
178	                    .and_then(|v| v.parse().ok())
179	                    .unwrap_or(1000u64);
180	                tokio::time::sleep(Duration::from_millis(ms)).await;
181	                ActionOutcome {
182	                    success: true,
183	                    error_message: None,
184	                    execution_time_ms: ms,
185	                    page_url_after: None,
186	                    dom_changed: false,
187	                }
188	            }
189	            ans_core::session::ActionType::Submit => {
190	                // Submit is typically handled as a click on a submit button
191	                // or pressing Enter. Evaluate a JS submit on the form.
192	                let selector = action.selector.as_deref().unwrap_or("form");
193	                let result = handle
194	                    .backend
195	                    .execute_script(&format!(
196	                        "(function(){{var f=document.querySelector('{}');if(f){{f.submit();return'ok'}}return'not found'}})()",
197	                        escape_for_js(selector)
198	                    ))
199	                    .await?;
200	                ActionOutcome {
201	                    success: result.contains("ok"),
202	                    error_message: if result.contains("ok") {
203	                        None
204	                    } else {
205	                        Some("form not found".into())
206	                    },
207	                    execution_time_ms: 0,
208	                    page_url_after: None,
209	                    dom_changed: true,
210	                }
211	            }
212	            ans_core::session::ActionType::Screenshot => {
213	                let _bytes = handle
214	                    .backend
215	                    .capture_screenshot(ans_core::backend::ImageFormat::Png, false)
216	                    .await?;
217	                ActionOutcome {
218	                    success: true,
219	                    error_message: None,
220	                    execution_time_ms: 0,
221	                    page_url_after: None,
222	                    dom_changed: false,
223	                }
224	            }
225	        };
226	
227	        Ok(outcome)
228	    }
