1	//! Browser pool — pre-launched Chromium instances for fast session creation.
2	//!
3	//! Maintains a pool of idle [`CdpBackend`] instances. When a session is
4	//! created, it acquires from the pool instead of cold-launching Chromium
5	//! (2-5s savings). When a session is closed, the backend is returned to
6	//! the pool for reuse.
7	//!
8	//! A background warmer task monitors the pool level and pre-launches new
9	//! backends when the idle count drops below `min_idle`.
10	
11	use std::collections::VecDeque;
12	use std::sync::Arc;
13	use std::time::Duration;
14	
15	use ans_cdp::CdpBackend;
16	use ans_core::backend::BrowserBackend;
17	use ans_stealth::StealthConfig;
18	use tokio::sync::Mutex;
19	use tracing;
20	
21	/// A pool of pre-launched Chromium backends.
22	///
23	/// Cheap to clone — wraps an `Arc<Mutex<VecDeque<CdpBackend>>>`.
24	#[derive(Clone)]
25	pub struct BrowserPool {
26	    idle: Arc<Mutex<VecDeque<CdpBackend>>>,
27	    max_size: usize,
28	    min_idle: usize,
29	}
30	
31	impl BrowserPool {
32	    /// Create a new browser pool.
33	    ///
34	    /// `max_size` caps the total idle backends. The warmer maintains
35	    /// at least `min_idle` backends (clamped to `max_size`).
36	    #[must_use]
37	    pub fn new(max_size: usize) -> Self {
38	        let min_idle = (max_size / 2).max(1);
39	        Self {
40	            idle: Arc::new(Mutex::new(VecDeque::with_capacity(max_size))),
41	            max_size,
42	            min_idle,
43	        }
44	    }
45	
46	    /// Create a pool with explicit min/max bounds.
47	    #[must_use]
48	    pub fn with_bounds(max_size: usize, min_idle: usize) -> Self {
49	        Self {
50	            idle: Arc::new(Mutex::new(VecDeque::with_capacity(max_size))),
51	            max_size,
52	            min_idle: min_idle.min(max_size),
53	        }
54	    }
55	
56	    /// Acquire a backend: pop from pool if available, else launch fresh.
57	    ///
58	    /// This is the hot path — called on every `SessionManager::create()`.
59	    pub async fn acquire(&self) -> Result<CdpBackend, ans_core::backend::BrowserError> {
60	        // Fast path: pop from idle pool
61	        if let Some(backend) = self.idle.lock().await.pop_front() {
62	            let idle_count = self.idle_bytes().await;
63	            tracing::debug!(pool_idle = idle_count, "Acquired backend from pool");
64	            return Ok(backend);
65	        }
66	
67	        // Slow path: cold launch
68	        tracing::info!("Pool empty, cold-launching Chromium");
69	        CdpBackend::launch(Some(StealthConfig::standard())).await
70	    }
71	
72	    /// Release a backend back to the pool.
73	    ///
74	    /// If the pool is at capacity, the backend is closed instead.
75	    /// Called on every `SessionManager::close()`.
76	    pub async fn release(&self, backend: CdpBackend) {
77	        let mut idle = self.idle.lock().await;
78	        if idle.len() < self.max_size {
79	            idle.push_back(backend);
80	            tracing::debug!(pool_idle = idle.len(), "Returned backend to pool");
81	        } else {
82	            drop(idle);
83	            tracing::debug!("Pool full, closing backend");
84	            let _ = backend.close().await;
85	        }
86	    }
87	
88	    /// Shut down the pool, closing all idle backends.
89	    pub async fn shutdown(&self) {
90	        let backends: Vec<CdpBackend> = self.idle.lock().await.drain(..).collect();
91	        tracing::info!(count = backends.len(), "Shutting down browser pool");
92	        for backend in backends {
93	            let _ = backend.close().await;
94	        }
95	    }
96	
97	    /// Number of idle backends currently in the pool.
98	    #[must_use]
99	    pub async fn idle_count(&self) -> usize {
100	        self.idle.lock().await.len()
101	    }
102	
103	    /// Background task: maintain `min_idle` backends in the pool.
104	    ///
105	    /// Runs indefinitely — `tokio::spawn` this at daemon startup.
106	    /// The task exits when all clones of `BrowserPool` are dropped
107	    /// (the `Arc` refcount drops to zero and `Mutex` is no longer
108	    ///  held by any holder).
109	    pub async fn warmer_task(&self) {
110	        let mut interval = tokio::time::interval(Duration::from_millis(500));
111	        loop {
112	            interval.tick().await;
113	            let current = self.idle_count().await;
114	            if current < self.min_idle {
115	                let needed = self.min_idle - current;
116	                tracing::debug!(current, needed, "Warmer: pre-launching backends");
117	                for _ in 0..needed {
118	                    match CdpBackend::launch(Some(StealthConfig::standard())).await {
119	                        Ok(backend) => {
120	                            let mut idle = self.idle.lock().await;
121	                            if idle.len() < self.max_size {
122	                                idle.push_back(backend);
123	                            } else {
124	                                drop(idle);
125	                                let _ = backend.close().await;
126	                                break; // pool is full, stop launching
127	                            }
128	                        }
129	                        Err(e) => {
130	                            tracing::warn!(error = %e, "Warmer: failed to pre-launch backend");
131	                            // Don't break — transient errors happen, retry next tick
132	                        }
133	                    }
134	                }
135	            }
136	        }
137	    }
138	
139	    /// Launch the warmer as a spawned background task.
140	    ///
141	    /// Returns the `JoinHandle` so callers can abort on shutdown.
142	    pub fn spawn_warmer(&self) -> tokio::task::JoinHandle<()> {
143	        let pool = self.clone();
144	        tokio::spawn(async move { pool.warmer_task().await })
145	    }
146	
147	    /// Approximate idle byte footprint (for debug logging).
148	    async fn idle_bytes(&self) -> usize {
149	        self.idle.lock().await.len()
150	    }
151	}
152	
