184	    async fn create_session(
185	        &self,
186	        request: Request<CreateSessionRequest>,
187	    ) -> Result<Response<Session>, Status> {
188	        let req = request.into_inner();
189	        let goal_id = parse_uuid(&req.goal_id, "goal_id")?;
190	        let start_url = optional_string(&req.start_url);
191	
192	        let session_id = self
193	            .sessions
194	            .create(goal_id, start_url)
195	            .await
196	            .map_err(|e| Status::internal(e.to_string()))?;
197	
198	        let now = now_epoch_ms();
199	        self.metrics.inc_sessions(1);
200	
201	        Ok(Response::new(Session {
202	            session_id: session_id.to_string(),
203	            goal_id: req.goal_id,
204	            status: "idle".into(),
205	            current_page: None,
206	            created_at: now,
207	            last_activity_at: now,
208	        }))
209	    }
