213	        request: Request<CloseSessionRequest>,
214	    ) -> Result<Response<Empty>, Status> {
215	        let req = request.into_inner();
216	        let session_id = parse_uuid(&req.session_id, "session_id")?;
217	        self.sessions
218	            .close(session_id)
219	            .await
220	            .map_err(|e| Status::internal(e.to_string()))?;
221	        self.metrics.inc_sessions(-1);
