625	    async fn classify_distractions(
626	        &self,
627	        request: Request<DistractionRequest>,
628	    ) -> Result<Response<DistractionList>, Status> {
629	        let req = request.into_inner();
630	        let url = req.url;
631	
632	        // Extract CSS class/id hints from DOM elements for distraction pattern matching
633	        let css_hints = req
634	            .dom
635	            .as_ref()
636	            .map(|dom| {
637	                dom.elements
638	                    .iter()
639	                    .flat_map(|el| {
640	                        el.attributes
641	                            .iter()
642	                            .filter(|(k, _)| *k == "class" || *k == "id")
643	                            .map(|(_, v)| v.clone())
644	                    })
645	                    .collect::<Vec<_>>()
646	                    .join(" ")
647	            })
648	            .unwrap_or_default();
649	
650	        // Extract all visible text from the distilled DOM for content scanning
651	        let dom_text = req
652	            .dom
653	            .as_ref()
654	            .map(|dom| {
655	                dom.elements
656	                    .iter()
657	                    .map(|el| el.text.as_str())
658	                    .collect::<Vec<_>>()
659	                    .join(" ")
660	            })
661	            .unwrap_or_default();
662	
663	        self.metrics.inc_immune_scans();
664	        let classifier = ans_immune::DistractionClassifier;
665	        let flags = classifier.classify(&url, &dom_text, &css_hints);
666	
667	        let distractions: Vec<_> = flags
668	            .iter()
669	            .map(ans_immune::serialization::distraction_to_proto_list_item)
670	            .collect();
671	
672	        Ok(Response::new(DistractionList {
673	            distractions,
674	            classification_time_us: 0,
675	        }))
676	    }
