880	fn proto_to_core_action(
881	    proto: &ans_proto::ans::Action,
882	) -> Result<ans_core::session::Action, Status> {
883	    use ans_core::session::ActionType;
884	    use std::collections::HashMap;
885	
886	    let action_type = match proto.action_type.as_str() {
887	        "click" => ActionType::Click,
888	        "type" => ActionType::Type,
889	        "scroll" => ActionType::Scroll,
890	        "select" => ActionType::Select,
891	        "navigate" => ActionType::Navigate,
892	        "wait" => ActionType::Wait,
893	        "submit" => ActionType::Submit,
894	        "screenshot" => ActionType::Screenshot,
895	        other => {
896	            return Err(Status::invalid_argument(format!(
897	                "unknown action_type: {other}"
898	            )))
899	        }
900	    };
901	
902	    Ok(ans_core::session::Action {
903	        action_type,
904	        selector: optional_string(&proto.selector),
905	        value: optional_string(&proto.value),
906	        params: proto
907	            .params
908	            .iter()
909	            .map(|(k, v)| (k.clone(), v.clone()))
910	            .collect::<HashMap<_, _>>(),
911	    })
912	}
913	
914	/// Map [`GoalStatus`] to a streaming event type string.
915	fn goal_status_event(status: ans_core::goal::GoalStatus) -> String {
916	    match status {
917	        ans_core::goal::GoalStatus::Pending => "created",
918	        ans_core::goal::GoalStatus::Active => "progress",
919	        ans_core::goal::GoalStatus::Completed => "completed",
920	        ans_core::goal::GoalStatus::Failed => "failed",
921	        ans_core::goal::GoalStatus::Blocked => "blocked",
922	    }
923	    .into()
924	}
925	
926	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
927	/// Returns `None` if the `eye_name` is unrecognized or the content is missing.
928	fn proto_to_core_eye_report(
929	    proto: &ans_proto::ans::EyeReport,
930	) -> Option<ans_core::signal::EyeReport> {
931	    use ans_proto::ans::eye_report::Content;
932	
933	    let eye_name = match proto.eye_name.as_str() {
934	        "dom_reader" => EyeName::DomReader,
935	        "vision" => EyeName::Vision,
936	        "page_diff" => EyeName::PageDiff,
937	        "goal_verifier" => EyeName::GoalVerifier,
938	        "error_detector" => EyeName::ErrorDetector,
939	        _ => return None,
940	    };
941	
942	    let content = match &proto.content {
943	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
944	            elements: vec![],
945	            interactive: vec![],
946	            mode: dom
947	                .dom
948	                .as_ref()
949	                .map_or(DistillMode::AllFields, |d| match d.mode.as_str() {
950	                    "text_only" => DistillMode::TextOnly,
951	                    "input_fields" => DistillMode::InputFields,
952	                    _ => DistillMode::AllFields,
953	                }),
954	        },
955	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
956	            visible_elements: v.visible_elements.clone(),
957	            overlays: v.overlays.clone(),
958	            blocked_regions: v.blocked_regions.clone(),
959	            page_type: v.page_type.clone(),
960	            anomalies: v.anomalies.clone(),
961	            raw_response: v.raw_response.clone(),
962	        },
963	        Some(Content::Diff(d)) => {
964	            let diff_report = d.diff.as_ref();
965	            EyeReportContent::DiffReport {
966	                added: diff_report.map_or(vec![], |r| {
967	                    r.added.iter().map(|e| e.selector.clone()).collect()
968	                }),
969	                removed: diff_report.map_or(vec![], |r| {
970	                    r.removed.iter().map(|e| e.selector.clone()).collect()
971	                }),
972	                modified: diff_report.map_or(vec![], |r| {
973	                    r.modified.iter().map(|m| m.selector.clone()).collect()
974	                }),
975	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
976	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
977	            }
978	        }
979	        Some(Content::Verification(v)) => EyeReportContent::Verification {
980	            sub_goal_advanced: v.criteria_status == "met",
981	            confidence: v.confidence,
982	            reasoning: v.reasoning.clone(),
983	            criteria_status: v.criteria_status.clone(),
984	        },
985	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
986	            failure_type: e.failure_type.clone(),
987	            description: e.description.clone(),
988	            recovery_actions: e.recovery_actions.clone(),
989	            should_retry: e.should_retry,
990	            max_retries: e.max_retries as u32,
991	        },
992	        None => return None,
993	    };
994	
995	    Some(ans_core::signal::EyeReport {
996	        eye_name,
997	        timestamp: chrono::Utc::now(),
998	        confidence: proto.confidence,
999	        goal_relevance: proto.goal_relevance,
1000	        content,
1001	    })
1002	}
1003	
1004	/// Format the oneof eye report content into a readable string.
1005	fn format_eye_content(content: Option<&ans_proto::ans::eye_report::Content>) -> String {
1006	    use ans_proto::ans::eye_report::Content;
1007	    match content {
1008	        Some(Content::Dom(dom)) => {
1009	            format!(
1010	                "DOM: {} elements, {} interactive",
1011	                dom.dom.as_ref().map_or(0, |d| d.elements.len() as i32),
1012	                dom.focused_elements.len()
1013	            )
1014	        }
1015	        Some(Content::Vision(v)) => {
1016	            format!(
1017	                "Vision: {} visible, {} overlays, type={}",
1018	                v.visible_elements.len(),
1019	                v.overlays.len(),
1020	                v.page_type
1021	            )
1022	        }
1023	        Some(Content::Diff(d)) => {
1024	            format!(
1025	                "Diff: {}% visual change",
1026	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
1027	            )
1028	        }
1029	        Some(Content::Verification(v)) => {
1030	            format!(
1031	                "Verify: {} (confidence={:.0}%)",
1032	                v.criteria_status,
1033	                v.confidence * 100.0
1034	            )
1035	        }
1036	        Some(Content::Error(e)) => {
1037	            format!("Error: {} — {}", e.failure_type, e.description)
1038	        }
1039	        None => "no content".into(),
1040	    }
1041	}
